codigoEjemplo:
# Verificar versión actual de Java
java -version
# Output: openjdk version "17.0.9" 2023-10-17

# Verificar versiones disponibles (con sdkman)
sdk list java
# Output:
# 21.0.1-tem    (Temurin 21 LTS)
# 17.0.9-tem    (Temurin 17 LTS)
# 11.0.21-tem   (Temurin 11 LTS)

# Instalar Java 17 con sdkman
sdk install java 17.0.9-tem

# Cambiar versión por defecto
sdk default java 17.0.9-tem

# Usar versión específica en terminal actual
sdk use java 17.0.9-tem

# Features de Java 17

// Records (clases de datos inmutables)
public record CustomerDTO(Long id, String name, String email) {}

// Antes (Java 8-16):
public class CustomerDTO {
    private final Long id;
    private final String name;
    private final String email;

    public CustomerDTO(Long id, String name, String email) {
        this.id = id;
        this.name = name;
        this.email = email;
    }

    // getters, equals, hashCode, toString...
}

// Pattern matching for instanceof
public String process(Object obj) {
    if (obj instanceof String s) {
        return s.toUpperCase();  // 's' ya es String
    }
    return "";
}

// Antes:
public String process(Object obj) {
    if (obj instanceof String) {
        String s = (String) obj;  // Cast manual
        return s.toUpperCase();
    }
    return "";
}

